1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	const COMPONENT_INSURANCE_VALUE = 250;
6	const CURSE_SURCHARGE_RATE = 0.5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const LOYALTY_DISCOUNT_RATE = 0.2;
11	const LOYALTY_YEARS_THRESHOLD = 2;
12	const FOLLOWUP_DISCOUNT_RATE = 0.15;
13	const DEDUCTIBLE = 100;
14	const CAP_MULTIPLIER = 2;
15	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
16	const HALF_PAYOUT_RATE = 0.5;
17	
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	};
24	
25	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	};
31	
32	const KNOWN_COMPONENT_TYPES = new Set(["rune", "moonstone"]);
33	
34	const isKnownItemType = (type: string): boolean =>
35	  type in BASE_PREMIUM_BY_TYPE || KNOWN_COMPONENT_TYPES.has(type);
36	
37	type Item = {
38	  type: string;
39	  material?: string;
40	  enchantment?: number;
41	  cursed?: boolean;
42	};
43	type Damage = { itemType: string; amount: number };
44	type Incident = { cause: string; damages: Damage[] };
45	type QuoteStep = { op: "quote"; items: Item[] };
46	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
47	type Step = QuoteStep | ClaimStep;
48	type Customer = { yearsWithMHPCO: number; firstQuote?: boolean };
49	type Scenario = { customer: Customer; steps: Step[] };
50	
51	const componentGroupPremium = (count: number): number =>
52	  count === COMPONENT_BLOCK_SIZE
53	    ? COMPONENT_BLOCK_PREMIUM
54	    : count * COMPONENT_BASE_PREMIUM;
55	
56	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
57	
58	const isHighEnchantment = (item: Item): boolean =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
60	
61	const qualifiesForFirstInsurance = (item: Item, isSingleItemPolicy: boolean): boolean =>
62	  isSingleItemPolicy && !!item.cursed && !isHighEnchantment(item);
63	
64	const surchargeRates = (item: Item, isSingleItemPolicy: boolean): number[] => [
65	  item.cursed ? CURSE_SURCHARGE_RATE : 0,
66	  isHighEnchantment(item) ? HIGH_ENCHANTMENT_RATE : 0,
67	  qualifiesForFirstInsurance(item, isSingleItemPolicy) ? FIRST_INSURANCE_RATE : 0,
68	];
69	
70	const mainItemPremium = (item: Item, isSingleItemPolicy: boolean): number => {
71	  const base = BASE_PREMIUM_BY_TYPE[item.type];
72	  const totalRate = surchargeRates(item, isSingleItemPolicy).reduce((a, b) => a + b, 1);
73	  return base * totalRate;
74	};
75	
76	const countByType = (items: Item[]): Map<string, number> =>
77	  items.reduce(
78	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
79	    new Map<string, number>(),
80	  );
81	
82	const sumComponentPremiums = (components: Item[]): number =>
83	  [...countByType(components).values()]
84	    .reduce((sum, count) => sum + componentGroupPremium(count), 0);
85	
86	const partitionItems = (items: Item[]): { mains: Item[]; components: Item[] } =>
87	  items.reduce<{ mains: Item[]; components: Item[] }>(
88	    (acc, item) => {
89	      (isMainItem(item) ? acc.mains : acc.components).push(item);
90	      return acc;
91	    },
92	    { mains: [], components: [] },
93	  );
94	
95	const sumItemPremiums = (items: Item[], policyRate: number): number => {
96	  const { mains, components } = partitionItems(items);
97	  const isSingleItemPolicy = items.length === 1;
98	  const { baseSum, premiumSum } = mains.reduce(
99	    (acc, item) => ({
100	      baseSum: acc.baseSum + BASE_PREMIUM_BY_TYPE[item.type],
101	      premiumSum: acc.premiumSum + mainItemPremium(item, isSingleItemPolicy),
102	    }),
103	    { baseSum: 0, premiumSum: 0 },
104	  );
105	  const componentsSum = sumComponentPremiums(components);
106	  return premiumSum + componentsSum + (baseSum + componentsSum) * policyRate;
107	};
108	
109	const customerRateAdjustments = (customer: Customer, isFollowUp: boolean): number[] => [
110	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? -LOYALTY_DISCOUNT_RATE : 0,
111	  customer.firstQuote ? FIRST_INSURANCE_RATE : 0,
112	  isFollowUp ? -FOLLOWUP_DISCOUNT_RATE : 0,
113	];
114	
115	const policyWideRate = (customer: Customer, isFollowUp: boolean): number =>
116	  customerRateAdjustments(customer, isFollowUp).reduce((sum, rate) => sum + rate, 0);
117	
118	const ceilInFavor = (value: number): number => Math.ceil(Number(value.toFixed(6)));
119	
120	const floorInFavor = (value: number): number => Math.floor(value);
121	
122	const assertKnownItemTypes = (items: Item[]): void => {
123	  const unknown = items.find((item) => !isKnownItemType(item.type));
124	  if (unknown) throw new Error(`Unknown item type: ${unknown.type}`);
125	};
126	
127	const quotePremiumFor = (step: QuoteStep, customer: Customer, isFollowUp: boolean): { premium: number } => {
128	  assertKnownItemTypes(step.items);
129	  return {
130	    premium: ceilInFavor(sumItemPremiums(step.items, policyWideRate(customer, isFollowUp)) + PROCESSING_FEE),
131	  };
132	};
133	
134	const itemInsuranceValue = (item: Item): number =>
135	  isMainItem(item) ? INSURANCE_VALUE_BY_TYPE[item.type] : COMPONENT_INSURANCE_VALUE;
136	
137	const policyInsuranceSum = (items: Item[]): number =>
138	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
139	
140	const findPolicyItem = (policyItems: Item[], itemType: string): Item | undefined =>
141	  policyItems.find((item) => item.type === itemType);
142	
143	const halvesPayout = (item: Item | undefined): boolean =>
144	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD;
145	
146	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
147	  const policyItem = findPolicyItem(policyItems, damage.itemType);
148	  const reimbursed = halvesPayout(policyItem) ? damage.amount * HALF_PAYOUT_RATE : damage.amount;
149	  return Math.max(0, reimbursed - DEDUCTIBLE);
150	};
151	
152	const assertDamagesMatchPolicy = (damages: Damage[], policyItems: Item[]): void => {
153	  const orphan = damages.find((d) => !findPolicyItem(policyItems, d.itemType));
154	  if (orphan) throw new Error(`Damage refers to item not in policy: ${orphan.itemType}`);
155	};
156	
157	const claimResult = (
158	  step: ClaimStep,
159	  policyItems: Item[],
160	  remainingCap: number,
161	): { payout: number; remainingCap: number } => {
162	  assertDamagesMatchPolicy(step.incident.damages, policyItems);
163	  const rawPayout = step.incident.damages.reduce((sum, d) => sum + damagePayout(d, policyItems), 0);
164	  const payout = floorInFavor(Math.min(rawPayout, remainingCap));
165	  return { payout, remainingCap: remainingCap - payout };
166	};
167	
168	const policyItemsAt = (scenario: Scenario, policyIndex: number): Item[] =>
169	  (scenario.steps[policyIndex] as QuoteStep).items;
170	
171	const policyCap = (scenario: Scenario, policyIndex: number): number =>
172	  policyInsuranceSum(policyItemsAt(scenario, policyIndex)) * CAP_MULTIPLIER;
173	
174	type RunState = { results: unknown[]; remainingCaps: Map<number, number> };
175	
176	const runStep = (state: RunState, step: Step, index: number, scenario: Scenario): RunState => {
177	  if (step.op === "quote") {
178	    state.results.push(quotePremiumFor(step, scenario.customer, index > 0));
179	    return state;
180	  }
181	  const remainingCap = state.remainingCaps.get(step.policy) ?? policyCap(scenario, step.policy);
182	  const result = claimResult(step, policyItemsAt(scenario, step.policy), remainingCap);
183	  state.remainingCaps.set(step.policy, result.remainingCap);
184	  state.results.push(result);
185	  return state;
186	};
187	
188	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
189	  const initial: RunState = { results: [], remainingCaps: new Map() };
190	  const final = scenario.steps.reduce(
191	    (state, step, i) => runStep(state, step, i, scenario),
192	    initial,
193	  );
194	  return { results: final.results };
195	};
